sys_script_client.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
		//HT - STRY0053832
	if(newValue == ''){
		return;
	}

	var sysId = g_form.getValue("parent");
	var recipient = g_form.getValue("u_recipient");

	var ajax = new GlideAjax('ClientTaskerEmailScripts');

	ajax.addParam('sysparm_name', 'populateTaskerEmailForm');
	ajax.addParam('sysparm_sysId', sysId);

	ajax.getXML(function(response){
		try{

			var data = response.responseXML.documentElement.getAttribute("answer");
			var exportAttachmentsOrDocs = JSON.parse(data);

			//the values related to attachments and documents or boolean values coming from the script include "ClientTaskerEmailScripts"
			// we use these values to determine if the checkboxes will be visible or not
			//the taskNumber is used for populating the default subject and body
			//the userName is use forthe deafult body of the email
			var enableMyAttachments = exportAttachmentsOrDocs.exportAttachments;
			// STRY0071517 was pointing at shared Documents variable instead of Shared Attachments
			var enableAttachAndDocs = exportAttachmentsOrDocs.exportAllSharedAttachments;
			var enableMyDocs = exportAttachmentsOrDocs.exportMyDocs;
			// STRY0071517 was pointing at shared Attachments variable instead of Shared Documents
			var enableAllSharedDocs =  exportAttachmentsOrDocs.exportAllSharedDocuments;
			var subject = exportAttachmentsOrDocs.subject.toString();
			var body = exportAttachmentsOrDocs.body.toString();
			// STRY0071517
			var recipients = exportAttachmentsOrDocs.recipients;

			g_form.setReadOnly('parent.classification', true);
			g_form.setValue("u_subject", subject);
			g_form.showFieldMsg('u_recipient','You will be copied on this task export automatically.','info', false);
			g_form.setValue("u_body", body);
			g_form.setDisplay("u_export_my_attachments", enableMyAttachments);
			// STRY0071517 was pointing at shared Documents variable instead of Shared Attachments
			g_form.setDisplay("u_export_all_shared_attachments", enableAttachAndDocs);
			g_form.setDisplay("u_export_my_documents", enableMyDocs);
			// STRY0071517 was pointing at shared Attachments variable instead of Shared Documents
			g_form.setDisplay("u_export_all_shared_documents", enableAllSharedDocs);
			// STRY0071517
			g_form.setValue("u_recipient", recipients);
		}catch(e){		
			jslog(e);
		}

	});

}
